import React, { useState } from "react";
import axios from "axios";
import Api from "../api/Api";
import { useLocation, useNavigate } from "react-router-dom";

const Login = () => {
  const location = useLocation();
  const navigate = useNavigate();

  const mobile = location.state?.mobile;

  const [otp, setOtp] = useState("");

  const handleVerify = async (e) => {
    e.preventDefault();

    try {
      const res = await axios.post(Api.verify_otp, {
        mobile,
        otp,
      });

      alert(res.data.message);

      navigate("/dashboard"); // optional

    } catch (err) {
      alert(err.response?.data?.message || "OTP Failed");
    }
  };

  if (!mobile) {
    return (
      <h2 className="text-center mt-10">
        Please SignUp first
      </h2>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-100">

      <div className="bg-white p-8 rounded-xl w-full max-w-md shadow-lg">

        <img
          src="garbageVehicle.jpeg"
          className="w-24 h-24 mx-auto mb-4"
          alt="img"
        />

        <h1 className="text-2xl text-center font-bold text-green-700">
          OTP Verification
        </h1>

        <p className="text-center text-gray-500 mb-6">
          Mobile: {mobile}
        </p>

        <form onSubmit={handleVerify} className="space-y-4">

          <input
            value={otp}
            onChange={(e) => setOtp(e.target.value)}
            placeholder="Enter OTP"
            className="w-full border p-2 rounded text-center tracking-widest"
            required
          />

          <button className="w-full bg-green-600 text-white p-2 rounded">
            Verify OTP
          </button>

        </form>
      </div>
    </div>
  );
};

export default Login;
